// // This module implements an 8-bit shift register with parallel load capability.
// It has a synchronous reset signal to initialize all bits to 0,
// a synchronous load signal to load an 8-bit value into the register,
// and a shift direction signal to control whether the register shifts left or right.
// The register should shift its contents on each negative edge of the clock signal when the load signal is low.
module shift_register_8bit_with_load(
    input wire clk,
    input wire rst,
    input wire load,
    input wire [7:0] load_value,
    input wire shift_dir,
    output reg [7:0] q
);

    always @(posedge clk) begin
        if (rst) begin
            q <= 8'b00000000;
        end else if (load) begin
            q <= load_value;
        end else if (shift_dir) begin
            q <= {q[6:0], 1'b0};  // Left shift
        end else begin
            q <= {1'b0, q[7:1]};  // Right shift
        end
    end
endmodule

